import{_ as a,o,c as t,a3 as n}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"Web Canvas (Agent 协作画布)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/web-canvas/index.md","filePath":"user-guide/tools/web-canvas/index.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/web-canvas/index.md"};function i(l,e,s,d,g,c){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="web-canvas-agent-协作画布" tabindex="-1">Web Canvas (Agent 协作画布) <a class="header-anchor" href="#web-canvas-agent-协作画布" aria-label="Permalink to &quot;Web Canvas (Agent 协作画布)&quot;">​</a></h1><p>Web Canvas 是一个基于 <strong>Physical-First (物理优先)</strong> 架构的 Agent 协作开发环境。它不仅提供了一个内置的代码编辑器和实时预览引擎，更核心的价值在于其深度集成的 <strong>LLM Agent 协作能力</strong>，允许智能体直接读写项目文件、感知运行时错误并进行迭代修复。</p><h2 id="_1-核心设计原理" tabindex="-1">1. 核心设计原理 <a class="header-anchor" href="#_1-核心设计原理" aria-label="Permalink to &quot;1. 核心设计原理&quot;">​</a></h2><p>Web Canvas 的设计围绕着“协作”与“物理真实”展开：</p><ul><li><strong>Physical-First 架构</strong>：与传统的内存虚拟文件系统不同，Web Canvas 所有的编辑操作（无论是用户手动输入还是 Agent 调用工具）都<strong>直接作用于物理磁盘</strong>。</li><li><strong>Git 版本追踪</strong>：每个画布项目都是一个独立的 Git 仓库。物理文件的任何变动都会被 Git 实时捕捉，提供可靠的变更追踪（Dirty Files）和回滚能力。</li><li><strong>独立预览通信</strong>：预览引擎运行在独立的系统窗口中，通过 <code>asset://</code> 协议加载物理文件，并通过注入脚本捕获所有运行时错误回传给主进程，形成“报错 -&gt; Agent 感知 -&gt; 修复”的闭环。</li></ul><hr><h2 id="_2-管理器操作-project-lobby" tabindex="-1">2. 管理器操作 (Project Lobby) <a class="header-anchor" href="#_2-管理器操作-project-lobby" aria-label="Permalink to &quot;2. 管理器操作 (Project Lobby)&quot;">​</a></h2><p>当你进入 Web Canvas 时，首先看到的是<strong>项目大厅</strong>，它是所有画布项目的管理中心。</p><h3 id="画布生命周期管理" tabindex="-1">画布生命周期管理 <a class="header-anchor" href="#画布生命周期管理" aria-label="Permalink to &quot;画布生命周期管理&quot;">​</a></h3><ul><li><strong>新建画布</strong>：点击左上角按钮，从<strong>模板系统</strong>初始化项目。模板决定了初始的文件结构（如 HTML/CSS/JS 组合）和入口文件。</li><li><strong>健康检查</strong>：管理器会定期对比磁盘物理目录与索引文件（<code>projects.json</code>）。如果发现索引丢失或物理目录被手动删除，会提供“修复”选项。</li><li><strong>物理删除</strong>：删除项目时，系统会将整个 Git 仓库目录移入系统回收站，确保数据安全。</li></ul><h3 id="视图与状态" tabindex="-1">视图与状态 <a class="header-anchor" href="#视图与状态" aria-label="Permalink to &quot;视图与状态&quot;">​</a></h3><ul><li><strong>卡片/列表切换</strong>：支持大卡片预览和紧凑列表模式。</li><li><strong>实时状态标签</strong>： <ul><li><code>正在编辑</code>：当前编辑器正打开此项目。</li><li><code>待提交</code>：物理文件已变更，但尚未执行 Git Commit。</li><li><code>同步中</code>：Agent 正在通过工具接口对该项目执行并发操作。</li></ul></li></ul><hr><h2 id="_3-画布独立窗口-preview-window" tabindex="-1">3. 画布独立窗口 (Preview Window) <a class="header-anchor" href="#_3-画布独立窗口-preview-window" aria-label="Permalink to &quot;3. 画布独立窗口 (Preview Window)&quot;">​</a></h2><p>预览窗口是 Web Canvas 的“眼睛”，它支持独立于主窗口运行，提供沉浸式的开发体验。</p><h3 id="实时预览引擎" tabindex="-1">实时预览引擎 <a class="header-anchor" href="#实时预览引擎" aria-label="Permalink to &quot;实时预览引擎&quot;">​</a></h3><ul><li><strong>物理加载</strong>：预览窗口不使用 <code>srcdoc</code> 字符串，而是通过 Tauri 提供的安全协议直接加载磁盘上的 <code>index.html</code>。</li><li><strong>防抖刷新</strong>：当磁盘文件发生变动时，预览引擎会触发 300ms 防抖刷新，既保证了实时性，又避免了因频繁保存导致的白屏闪烁。</li></ul><h3 id="运行时错误捕获" tabindex="-1">运行时错误捕获 <a class="header-anchor" href="#运行时错误捕获" aria-label="Permalink to &quot;运行时错误捕获&quot;">​</a></h3><p>预览窗口被注入了特制的监控脚本，能够捕获以下信息并实时回传：</p><ul><li><code>console.error</code> / <code>console.warn</code></li><li><code>window.onerror</code> (未捕获的常规错误)</li><li><code>unhandledrejection</code> (未捕获的 Promise 异常)</li></ul><p>这些错误不仅展示在预览窗口的控制台中，还会被同步到 <strong>Agent 上下文</strong>中。</p><hr><h2 id="_4-agent-配置联动-agent-integration" tabindex="-1">4. Agent 配置联动 (Agent Integration) <a class="header-anchor" href="#_4-agent-配置联动-agent-integration" aria-label="Permalink to &quot;4. Agent 配置联动 (Agent Integration)&quot;">​</a></h2><p>这是 Web Canvas 最强大的部分——将画布变成 Agent 的“操盘工具”。</p><h3 id="绑定与感知" tabindex="-1">绑定与感知 <a class="header-anchor" href="#绑定与感知" aria-label="Permalink to &quot;绑定与感知&quot;">​</a></h3><p>在 <strong>智能体 (Agent) 设置</strong> 或 <strong>画布设置</strong> 中，你可以配置联动参数：</p><ul><li><strong>绑定画布 ID</strong>：通过 <code>canvas-bound-id</code> 明确告诉 Agent 当前应该操作哪一个项目。</li><li><strong>自动包含运行时错误</strong>：开启后，预览窗口捕获的错误会作为“额外上下文”自动发送给 Agent。Agent 能够根据报错信息定位到具体文件的行号，实现自愈。</li></ul><h3 id="agent-工具集-toolbox" tabindex="-1">Agent 工具集 (Toolbox) <a class="header-anchor" href="#agent-工具集-toolbox" aria-label="Permalink to &quot;Agent 工具集 (Toolbox)&quot;">​</a></h3><p>Agent 拥有操作画布的完整权限：</p><ol><li><strong>读取文件</strong>：获取带行号的源码。</li><li><strong>应用 Diff</strong>：使用先进的 Search/Replace 算法进行手术式代码修改。</li><li><strong>提交/回滚</strong>：Agent 可以在完成阶段性任务后自动执行 <code>commit</code>，或在测试失败时 <code>discard</code> 更改。</li></ol><h3 id="审批流联动" tabindex="-1">审批流联动 <a class="header-anchor" href="#审批流联动" aria-label="Permalink to &quot;审批流联动&quot;">​</a></h3><p>当 Agent 发起文件修改请求时，Web Canvas 会采用**“先应用，后确认”**的策略：</p><ol><li>Agent 修改物理文件。</li><li>预览窗口实时刷新展示修改后的效果。</li><li>用户在预览窗口中直接观察效果，若满意则批准（保留修改），若不满意则拒绝（系统自动通过 Git 回滚物理文件）。</li></ol><hr><h2 id="_5-进阶技巧" tabindex="-1">5. 进阶技巧 <a class="header-anchor" href="#_5-进阶技巧" aria-label="Permalink to &quot;5. 进阶技巧&quot;">​</a></h2><ul><li><strong>外部编辑器协作</strong>：由于是物理优先架构，你可以同时用 VSCode 打开画布目录进行重构，Web Canvas 会自动同步 Git 状态。</li><li><strong>自定义模板</strong>：你可以将常用的框架结构存放在 <code>AppData/canvases/templates/user/</code> 下，实现一键生成专属开发环境。</li><li><strong>错误过期机制</strong>：当你手动修复代码后，预览窗口会自动将之前的错误标记为“过期 (Stale)”，确保 Agent 不会被旧的报错干扰。</li></ul>',36)])])}const b=a(r,[["render",i]]);export{u as __pageData,b as default};
